```cpp
#include <iostream>
#include <unistd.h>
#include <sys/wait.h>
#include <cstdio>

int main() {
    int pipefd[2];
    if (pipe(pipefd) == -1) {
        std::cerr << "Pipe failed" << std::endl;
        return 1;
    }

    pid_t pid = fork();
    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    } else if (pid > 0) { // Parent process
        close(pipefd[0]); // Close read end in parent
        std::string message = "Hello from parent!";
        write(pipefd[1], message.c_str(), message.length() + 1);
        close(pipefd[1]);
        wait(NULL); // Wait for child to finish
    } else { // Child process
        close(pipefd[1]); // Close write end in child
        dup2(pipefd[0], STDIN_FILENO); // Redirect stdin to pipe
        close(pipefd[0]);
        dup2(pipefd[0], STDOUT_FILENO); // Redirect stdout to pipe
        close(pipefd[0]);

        std::string data;
        std::cin >> data; // Read from pipe
        std::cout << "Received: " << data << std::endl;
        _exit(0);
    }

    return 0;
}
```

